            Err(diagnostic) => {
                return RowExecutionStatus::Failed {
                    diagnostics: vec![diagnostic],
                };
            }
        };
        let output_bytes = match applier.apply_delta(
            &source_bytes,
            &patch_bytes,
            context.integrity.expected_output_bytes,
        ) {
            Ok(bytes) => bytes,
            Err(error) => {
